// Extract Tally form fields
const body = $input.first().json.body || $input.first().json;
const fields = body.data?.fields || [];

let name = '';
let contact = '';
let answer = '';

fields.forEach(f => {
  const label = (f.label || '').toLowerCase();
  const val = Array.isArray(f.value) ? f.value.join(', ') : (f.value || '');
  if (label.includes('имя') || label.includes('name')) name = val;
  else if (label.includes('telegram') || label.includes('email') || label.includes('контакт')) contact = val;
  else if (label.includes('откли') || label.includes('ответ') || label.includes('сложн')) answer = val;
});

// Fallback: grab first 3 fields
if (!name && fields[0]) name = String(fields[0].value || '');
if (!contact && fields[1]) contact = String(fields[1].value || '');
if (!answer && fields[2]) answer = String(fields[2].value || '');

const timestamp = new Date().toLocaleString('ru-RU', { timeZone: 'Europe/Berlin' });

return [{ json: { name, contact, answer, timestamp } }];

// Log to n8n Data Table (optional, configure table ID)
// For now just pass through
const d = $input.first().json;
return [{ json: { logged: true, name: d.name, contact: d.contact } }];
